const { ApolloServer, gql } = require('apollo-server');
const { buildSchema } = require('graphql');

// Define the schema with nested relationships
const typeDefs = gql`
  type User {
    id: ID!
    name: String!
    posts: [Post]
  }

  type Post {
    id: ID!
    title: String!
    content: String!
    comments: [Comment]
    author: User
  }

  type Comment {
    id: ID!
    text: String!
    post: Post
    user: User
  }

  type Query {
    users: [User]
    posts: [Post]
    comments: [Comment]
    user(id: ID!): User
    post(id: ID!): Post
    comment(id: ID!): Comment
  }
`;

// Define the resolvers with nested relationships
const resolvers = {
  Query: {
    users: () => users,
    posts: () => posts,
    comments: () => comments,
    user: (_, { id }) => users.find(user => user.id === id),
    post: (_, { id }) => posts.find(post => post.id === id),
    comment: (_, { id }) => comments.find(comment => comment.id === id)
  },
  User: {
    posts: (user) => posts.filter(post => post.author.id === user.id),
    comments: (user) => comments.filter(comment => comment.user.id === user.id)
  },
  Post: {
    comments: (post) => comments.filter(comment => comment.post.id === post.id),
    author: (post) => users.find(user => user.id === post.author.id)
  },
  Comment: {
    post: (comment) => posts.find(post => post.id === comment.post.id),
    user: (comment) => users.find(user => user.id === comment.user.id)
  }
};

// Sample data for demonstration
const users = [
  { id: '1', name: 'Alice' },
  { id: '2', name: 'Bob' }
];

const posts = [
  { id: '1', title: 'Post 1', content: 'Content of Post 1', author: { id: '1' } },
  { id: '2', title: 'Post 2', content: 'Content of Post 2', author: { id: '2' } }
];

const comments = [
  { id: '1', text: 'Comment 1', post: { id: '1' }, user: { id: '1' } },
  { id: '2', text: 'Comment 2', post: { id: '1' }, user: { id: '2' } },
  { id: '3', text: 'Comment 3', post: { id: '2' }, user: { id: '1' } }
];

// Create the Apollo Server
const server = new ApolloServer({ typeDefs, resolvers });

// Start the server
server.listen().then(({ url }) => {
  console.log(`🚀 Server ready at ${url}`);
});